#include<bits/stdc++.h>
using namespace std;
const int N = 1e6+5;
int n,l,r,p[N],a,b,k,kk,ll,rr,s;
bool cmp(int x,int y){
    printf("? %d %d\n",x,y);
    fflush(stdout);
    scanf("%d",&kk);
    return kk==1?1:0;
}
void Insert(int m,int o){
    r++;
    for(int i=r;i>m;i--)p[i]=p[i-1];
    p[m]=o;
}
int main(){
    scanf("%d",&n);
    l=1,r=n;
    for(int i=1;i<=n;i++)p[i]=i;
    sort(p+1,p+n+1,cmp);
    n--;
    while(n--){
        a=p[l],b=p[r];l++,r--;
        printf("+ %d %d\n",a,b);
        fflush(stdout);
        scanf("%d",&k);
        ll=l,rr=r,s=r+1;
        while(ll<=rr){
            int mid=(ll+rr)/2;
            if(cmp(k,p[mid]))s=mid,rr=mid-1;
            else ll=mid+1;
        }
        Insert(s,k);
    }
    printf("!\n");
    fflush(stdout);
    return 0;
}
